from sys import stdin

n = int(stdin.readline())

a = [int(x) for x in stdin.readline().split()]

m = max(a)

for x in range(1, m + 1):
    for y in range(1, m + 1):
        if x * y < m:
            continue
        d = {a[0]: (1, 1)}
        for i in range(1, n):
            x1, y1 = d[a[i - 1]]
            if a[i] == x1 + 1:
                d[a[i]] = (x1 + 1, y1)
            elif a[i] == x1 - 1:
                d[a[i]] = (x1 - 1, y1)
            elif a[i] == y1 + 1:
                d[a[i]] = (x1, y1 + 1)
            elif a[i] == y1 - 1:
                d[a[i]] = (x1, y1 - 1)
            else:
                break
        else:
            print('YES')
            print(x, y)
            exit()
print('NO')
